+		if ctx.Question != "" {
+			b.WriteString(fmt.Sprintf("**Question:** %s\n\n", ctx.Question))
+		}
+		if ctx.Session != "" {
+			b.WriteString(fmt.Sprintf("**Session:** %s\n\n", ctx.Session))
+		}
+		if ctx.RunID != "" {
+			b.WriteString(fmt.Sprintf("**Run ID:** %s\n\n", ctx.RunID))
+		}
+	}
+
+	if f.Provenance != nil {
